VALUES
  ('promotion-d1056197-moex-00062', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '有關恩格爾曲線（Engelcurve），下列敘述何者正確？', '["恩格爾曲線是刻劃當所得變動時，所有財貨的消費量如何隨之變動", "若某商品的需求函數符合需求法則，則其恩格爾曲線為正斜率", "奢侈品的恩格爾曲線是負斜率", "恩格爾曲線若為一垂直線，則該財貨必定不是季芬財"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00063', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '對於繪製一廠商之等產量曲線，下列關於廠商的假設何者正確？', '["廠商至少使用一種固定投入", "廠商追求利潤極大化", "廠商具有技術效率", "廠商具有經濟效率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00064', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', 'A、B兩家廠商生產相同的產品。A廠商的製造過程高度自動化，有大量的固定成本，而B廠商 的製造主要依賴變動要素。假設兩家廠商的銷售數字相當，下列敘述何者正確？', '["A廠商較快可以達到損益平衡點", "當產量越來越大，A廠商的利潤率可能越高於B廠商的利潤率", "A廠商的短期供給曲線較B廠商的短期供給曲線平緩", "A廠商的短期供給曲線較長期供給曲線較平緩"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00065', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '有關完全競爭市場，下列敘述何者錯誤？', '["個別廠商所面對的需求曲線為水平線", "廠商總是在平均成本最低點生產", "若廠商有超額利潤，市場的廠商數目會增加", "若勞動市場是完全競爭市場，價格等於邊際成本條件亦決定最適勞動僱用水準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00066', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '假設一獨占廠商面對之市場需求函數為 Q=9P，而成本函數為 C(Q)=2+Q2；其中 P 為價格，Q 為數量。若該公司可採行完全差別定價，則其最適產量為何？', '["3", "2.5", "2.25", "2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00067', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '在相同的勞動供給與勞動需求結構下，考慮下列四種可能的勞動工資水準：勞動市場為完全競爭 下的工資水準 W 、勞動市場為勞方專賣下的工資水準 W 、勞動市場為資方專買下的工資水準 C S W 、與勞動市場同時為勞方專賣與資方專買下的工資水準W 。假設資方面對的商品市場是完全 B M 競爭，則下列敘述何者正確？', '["W ≦W ≦W ，且W ≧W B C S M C", "W ≦W ≦W ，且W ≦W S M B M C", "W ≦W ≦W ，但是W 有可能大於、小於或等於W S M B C M", "W ≦W ≦W ，但是W 有可能大於、小於或等於W B M S C M"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00068', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '下列何種情況最可能發生邊際勞動報酬遞減（diminishingmarginalreturnstolabor）？', '["當廠商僱用新進人員時，總是額外購買新設備供其使用", "當廠商僱用新進人員時，總是要求員工調配時間輪流共用現有設備", "當廠商購買新設備時，總是要求現有員工負責操作", "當廠商購買新設備時，總是僱用新進人員專門負責操作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00069', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '某品牌洗髮精廠商知道自己的產品品質很好，但一般消費者在使用前難以判斷洗髮精品質，該廠 商可採取下列何種策略處理消費者面對的資訊不對稱問題？', '["降價", "增加產能", "增加廣告", "增加研發經費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00070', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '有關公共財（publicgoods）的敘述，下列何者正確？', '["公共財具有排他性", "公共財具有敵對性", "公共財不具有敵對性且不具有排他性", "由政府生產給人民使用的財貨稱為公共財"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00071', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '根據貨幣數量學說，下列何者會造成平均物價上升的幅度小於貨幣供給數量增加的幅度？', '["實質產出增加或貨幣流通速度增加", "實質產出增加或貨幣流通速度減少", "實質產出減少或貨幣流通速度增加", "實質產出減少或貨幣流通速度減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL)
